    handleDrop,
    clearReferenceImage,
    updateCharacterData,
    updateEnvironmentData,
    updateGamePropsData,
    updateUserInterfaceData,
    updateUIAssetData,
    updateIconDesignData,
    updateVariantData,
    updateSoundEffectData,
    handleGeneratePalette,
    updateCreatureMix,
    addCreatureMix,
    removeCreatureMix,
    updateCreatureAdvanced,
    handleTextureGridUpdate,
    updateTextureSlot,
    randomizeSlot,
    handleAutoFillClick,
    onAutoFillFileChange,
    handleGenerate,
    handleAITextureGenerate,
    handleSaveJSON,
    handleLoadJSON,
    handleIconUpload,
    updateIconAdjusterData,
    updateIconItem,
    updateBgRemoverData,
    updateImageEditorData,
    updateAudioEditorData,
    handleSendToTool,
    handleSendRawImageToTool,
    updateEditState,
    handleForceAngle,
    handleVariantHue,
    handleTextureScan
  };
};

