                     <input type="range" min="0.01" max="1" step="0.01" value={data.scaleStep} onChange={(e) => updateIconAdjusterData({ scaleStep: parseFloat(e.target.value) })} className="w-full h-1 bg-zinc-800 rounded appearance-none cursor-pointer accent-blue-500" />
