    });
  };

  const updateIconAdjusterData = (updates: Partial<IconAdjusterData>) => {
    updateState(prev => ({
        iconAdjusterData: { ...prev.iconAdjusterData, ...updates }
    }));
  };

  const updateIconItem = (idOrIds: string | string[], updates: Partial<IconItem>) => {
      const ids = Array.isArray(idOrIds) ? idOrIds : [idOrIds];
      updateIconAdjusterData({
          items: state.iconAdjusterData.items.map(item => ids.includes(item.id) ? { ...item, ...updates } : item)
      });
  };

  const handleIconUpload = (files: FileList) => {
      const newItems: IconItem[] = Array.from(files).map(file => ({
          id: Date.now().toString() + Math.random(),
          file,
          src: URL.createObjectURL(file),
          x: 0, y: 0, scale: 1,
          originalWidth: 512, originalHeight: 512
      }));

      newItems.forEach(item => {
          const img = new Image();
          img.onload = () => {
              item.originalWidth = img.naturalWidth;
              item.originalHeight = img.naturalHeight;
          };
          img.src = item.src;
      });

      updateIconAdjusterData({
          items: [...state.iconAdjusterData.items, ...newItems]
      });
  };

  const handleSaveZip = async () => {
      const data = state.iconAdjusterData;
      if (data.items.length === 0) return;

      const zip = new JSZip();

      const drawItem = async (item: IconItem) => {
          const canvas = document.createElement('canvas');
          canvas.width = data.canvasWidth;
          canvas.height = data.canvasHeight;
          const ctx = canvas.getContext('2d');
          if (!ctx) return null;

          // Background
          if (data.background === 'white') {
              ctx.fillStyle = '#ffffff';
              ctx.fillRect(0, 0, canvas.width, canvas.height);
          } else if (data.background === 'black') {
              ctx.fillStyle = '#000000';
              ctx.fillRect(0, 0, canvas.width, canvas.height);
          } else if (data.background === 'custom') {
              ctx.fillStyle = data.backgroundColor;
              ctx.fillRect(0, 0, canvas.width, canvas.height);
          }

          const loadImg = (src: string) => new Promise<HTMLImageElement | null>((resolve) => {
              const img = new Image();
              img.crossOrigin = "Anonymous";
              img.onload = () => resolve(img);
              img.onerror = () => resolve(null);
              img.src = src;
          });

          try {
              const [img, overlayImg] = await Promise.all([
                  loadImg(item.src),
                  item.overlay ? loadImg(item.overlay.src) : Promise.resolve(null)
              ]);

